    const [currentUser, setCurrentUser] = useState<CurrentUser | null>(null);
    const [peers, setPeers] = useState<Record<string, Peer>>({});
    const [isMuted, setIsMuted] = useState(false);
    const [isVideoEnabled, setIsVideoEnabled] = useState(false);
    const [isScreenSharing, setIsScreenSharing] = useState(false);
    const [status, setStatus] = useState('Initializing...');
    const [fullScreenPeerId, setFullScreenPeerId] = useState<string | null>(null);
    const [connectionStatus, setConnectionStatus] = useState<RTCIceConnectionState>('new');

    // Refs
    const localStreamRef = useRef<MediaStream | null>(null);
    const peersRef = useRef<Record<string, Peer>>(peers);
    useEffect(() => {
      peersRef.current = peers;
    }, [peers]);

    const navigateToMessages = () => {
      navigate('/messages');
    };

    const toggleMute = () => {
      if (localStreamRef.current) {
        localStreamRef.current.getAudioTracks().forEach((track) => {
          track.enabled = !isMuted;
        });
        setIsMuted(!isMuted);
      }
    };

    const toggleVideo = () => {
      if (localStreamRef.current) {
        localStreamRef.current.getVideoTracks().forEach((track) => {
          track.enabled = !isVideoEnabled;
        });
        setIsVideoEnabled(!isVideoEnabled);
      }
    };

    const startScreenShare = async () => {
      try {
        const stream = await navigator.mediaDevices.getDisplayMedia({
          video: true,
        });

        stream.getTracks().forEach((track) => {
          for (const peerId in peersRef.current) {
            peersRef.current[peerId].connection.getSenders().forEach((sender) => {
              if (sender.track && sender.track.kind === track.kind) {
                sender.replaceTrack(track);
              }
            });
          }
        });

        localStreamRef.current = stream;
        setIsScreenSharing(true);
